// DJ OPUS - SECTION 7: PROGRESSIVE OUTRO
// Sasha closing set. Hypnotic. Drifting. Beautiful.
setcps(134/60/4)

let driftFilter = slider(1500, 200, 4000, 10, "DRIFT Filter")
let fadeOut = slider(0.7, 0, 1, 0.01, "FADE Level")

// Kick - softer now
let kick = s("bd").bank("RolandTR909")
  .gain(fadeOut.mul(0.85))
  .struct("x x x x")

// Minimal hats
let hats = s("hh").bank("RolandTR909")
  .gain(fadeOut.mul(0.3))
  .struct("~ x ~ x ~ x ~ x")
  .cutoff(3000)

// Rim click
let rim = s("sd").bank("RolandTR909")
  .gain(fadeOut.mul(0.2))
  .struct("~ [~ x] ~ ~")
  .speed(1.5)

// Hypnotic bass - perlin drift, never repeats
let bass = note("<a2 a2 a2 e2 a2 a2 g2 e2>")
  .s("sawtooth")
  .cutoff(perlin.range(200, driftFilter).slow(8))
  .resonance(12)
  .decay(0.2)
  .sustain(0.05)
  .gain(fadeOut.mul(0.55))
  .struct("x ~ x [~ x] x ~ x ~")

// Last diva echo - fading into the distance
let divaEcho = note("<[a3,e4] [e3,b3]>".slow(4))
  .s("gm_voice_oohs")
  .gain(fadeOut.mul(0.3))
  .room(1)
  .size(1)
  .delay(0.6)
  .delaytime(0.5)
  .delayfeedback(0.55)
  .cutoff(driftFilter)

// Deep pad - last warmth
let deepPad = note("<[a2,e3] [e2,b2] [a2,e3] [e2,b2]>".slow(4))
  .s("gm_pad_sweep")
  .gain(fadeOut.mul(0.25))
  .cutoff(perlin.range(300, 1500).slow(16))
  .room(0.9)
  .size(0.95)

// Distant crystal - final sparkle
let crystal = note("a5 ~ ~ ~ ~ ~ ~ ~".slow(2))
  .s("gm_fx_crystal")
  .gain(fadeOut.mul(0.08))
  .delay(0.8)
  .delaytime(0.5)
  .delayfeedback(0.7)
  .room(1)

stack(kick, hats, rim, bass, divaEcho, deepPad, crystal)
